  1	import * as React from 'react';
  2	import classnames from 'classnames';
  3	
  4	import { WizardTab } from '@catalog/wizard/tabs';
  5	import VirtualMachineModel from '@kubevirt-ui/kubevirt-api/console/models/VirtualMachineModel';
  6	import { AnnotationsModal } from '@kubevirt-utils/components/AnnotationsModal/AnnotationsModal';
  7	import { LabelsModal } from '@kubevirt-utils/components/LabelsModal/LabelsModal';
  8	import MetadataLabels from '@kubevirt-utils/components/MetadataLabels/MetadataLabels';
  9	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
 10	import SidebarEditor from '@kubevirt-utils/components/SidebarEditor/SidebarEditor';
 11	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 12	import { PATHS_TO_HIGHLIGHT } from '@kubevirt-utils/resources/vm/utils/constants';
 13	import {
 14	  DescriptionList,
 15	  PageSection,
 16	  PageSectionVariants,
 17	  pluralize,
 18	} from '@patternfly/react-core';
 19	
 20	import { WizardDescriptionItem } from '../../components/WizardDescriptionItem';
 21	
 22	import './wizard-metadata-tab.scss';
 23	
 24	const WizardMetadataTab: WizardTab = ({ loaded, updateVM, vm }) => {
 25	  const { t } = useKubevirtTranslation();
 26	  const { createModal } = useModal();
 27	
 28	  return (
 29	    <PageSection className="wizard-metadata-tab" variant={PageSectionVariants.light}>
 30	      <SidebarEditor
 31	        onResourceUpdate={(newVM) => updateVM(newVM)}
 32	        pathsToHighlight={PATHS_TO_HIGHLIGHT.DETAILS_TAB}
 33	        resource={vm}
 34	      >
 35	        {(resource) => (
 36	          <>
 37	            <DescriptionList
 38	              className={classnames(
 39	                'pf-v6-c-description-list',
 40	                'wizard-metadata-tab__description-list',
 41	              )}
 42	            >
 43	              <WizardDescriptionItem
 44	                description={
 45	                  <MetadataLabels labels={resource?.metadata?.labels} model={VirtualMachineModel} />
 46	                }
 47	                helperPopover={{
 48	                  content: t(
 49	                    'Map of string keys and values that can be used to organize and categorize (scope and select) objects',
 50	                  ),
 51	                  header: t('Labels'),
 52	                }}
 53	                onEditClick={() =>
 54	                  createModal(({ isOpen, onClose }) => (
 55	                    <LabelsModal
 56	                      onLabelsSubmit={(updatedLabels) =>
 57	                        updateVM((vmDraft) => {
 58	                          vmDraft.metadata.labels = updatedLabels;
 59	                        })
 60	                      }
 61	                      isOpen={isOpen}
 62	                      obj={vm}
 63	                      onClose={onClose}
 64	                    />
 65	                  ))
 66	                }
 67	                isDisabled={!loaded}
 68	                isEdit
 69	                showEditOnTitle
 70	                testId="wizard-metadata-labels"
 71	                title={t('Labels')}
 72	              />
 73	
 74	              <WizardDescriptionItem
 75	                description={pluralize(
 76	                  Object.values(resource?.metadata?.annotations || {})?.length,
 77	                  'annotation',
 78	                )}
 79	                helperPopover={{
 80	                  content: t(
 81	                    'Annotations is an unstructured key value map stored with a resource that may be set by external tools to store and retrieve arbitrary metadata. They are not queryable and should be preserved when modifying objects',
 82	                  ),
 83	                  header: t('Annotations'),
 84	                }}
 85	                onEditClick={() =>
 86	                  createModal(({ isOpen, onClose }) => (
 87	                    <AnnotationsModal
 88	                      onSubmit={(updatedAnnotations) =>
 89	                        updateVM((vmDraft) => {
 90	                          vmDraft.metadata.annotations = updatedAnnotations;
 91	                        })
 92	                      }
 93	                      isOpen={isOpen}
 94	                      obj={vm}
 95	                      onClose={onClose}
 96	                    />
 97	                  ))
 98	                }
 99	                isDisabled={!loaded}
100	                isEdit
101	                testId="wizard-metadata-annotations"
102	                title={t('Annotations')}
103	              />
104	            </DescriptionList>
105	          </>
106	        )}
107	      </SidebarEditor>
108	    </PageSection>
109	  );
110	};
111	
112	export default WizardMetadataTab;

